9		function runsListHref(): string {
10			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs`
11		}
12	
13		function parentRunHref(parentId: string): string {
14			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs/${parentId}`
15		}
16	
17		function childRunHref(childId: string): string {
18			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs/${childId}`
19		}
20	
21		function beadHref(beadId: string): string {
22			return `/nodes/${data.nodeId}/projects/${data.projectId}/beads/${beadId}`
23		}
24	
25		function artifactHref(artifactId: string): string {
26			return `/nodes/${data.nodeId}/projects/${data.projectId}/artifacts/${encodeURIComponent(artifactId)}`
27		}
28	
29		function fmtDate(iso: string | null): string {
30			if (!iso) return '—'
31			return new Date(iso).toLocaleString()
32		}
33	
34		function fmtDuration(ms: number | null): string {
35			if (ms == null) return '—'
36			if (ms < 1000) return `${ms}ms`
37			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`
38			const m = Math.floor(ms / 60_000)
39			const s = Math.floor((ms % 60_000) / 1000)
40			return `${m}m ${s}s`
41		}
42	
43		function layerBadgeClass(layer: string): string {
44			switch (layer) {
45				case 'work':
46					return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300'
47				case 'try':
48					return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300'
49				case 'run':
50					return 'bg-teal-100 text-teal-800 dark:bg-teal-900/30 dark:text-teal-300'
51				default:
52					return 'bg-bg-surface text-fg-muted dark:bg-dark-bg-surface dark:text-dark-fg-muted'
53			}
54		}
55	
56		function statusBadgeClass(status: string): string {
57			switch (status) {
58				case 'success':
59					return 'badge-status-closed'
60				case 'failure':
61					return 'badge-status-failed'
62				case 'running':
63					return 'badge-status-running'
64				case 'preserved':
65					return 'badge-status-in-progress'
66				default:
67					return 'badge-status-open'
68			}
69		}
70	
71		function breadcrumbs(): Array<{ label: string; href: string }> {
72			if (!run) return []
73			const crumbs: Array<{ label: string; href: string }> = [
74				{ label: 'Runs', href: runsListHref() }
75			]
76			if (run.layer === 'run' && data.grandparentRunId && run.parentRunId) {
77				crumbs.push({ label: data.grandparentRunId, href: parentRunHref(data.grandparentRunId) })
78				crumbs.push({ label: run.parentRunId, href: parentRunHref(run.parentRunId) })
79			} else if (run.parentRunId) {
80				crumbs.push({ label: run.parentRunId, href: parentRunHref(run.parentRunId) })
81			}
82			crumbs.push({ label: run.id, href: '#' })
83			return crumbs
84		}
