134	export const load: PageLoad = async ({ params, fetch }) => {
135		const client = createClient(fetch as unknown as typeof globalThis.fetch);
136		const data = await client.request<BeadResult>(BEAD_QUERY, {
137			id: params.beadId,
138			projectID: params.projectId
